# This file cannot run within Github repo, it is included here for documentation purposes only. 
# This script was used to collect the raw data during the tag experiment sessions. 
# The raw .csv files generated by this script are not included in the repository, but the cleaned and processed data is included in publish/data/events.csv.

#!/usr/bin/env python3
"""
Tag Experiment Tracker
Tracks who is the tagger and when role switches occur during a tag game.
"""

import csv
import os
import random
import select
import sys
import termios
import threading
import time
import tty
from datetime import datetime

# ============================================================================
# CONFIGURATION
# ============================================================================
NUM_PLAYERS         = 5
EXPERIMENT_DURATION = 120    # seconds (120 = 2 minutes)
EXPERIMENT_DIR      = "/Users/astrid/Desktop/ABM/Experiment"
CONDITION_LABELS    = {'B': 'BL', 'W': 'WIN', 'F': 'FUN'}
# ============================================================================


class TagExperiment:

    def __init__(self):
        self.data         = []
        self.log          = []   # every line printed, saved to .txt at the end
        self.start_time   = None
        self.end_time     = None
        self.running      = False
        self.group_number = None
        self.condition    = None

    def out(self, text=''):
        """Print a line and store it for the session log."""
        print(text)
        self.log.append(text)

    def get_key(self, timeout=0.2):
        """Read a single keypress from the terminal. Returns None on timeout."""
        fd = sys.stdin.fileno()
        old_settings = termios.tcgetattr(fd)
        try:
            tty.setraw(fd)
            ready, _, _ = select.select([sys.stdin], [], [], timeout)
            if ready:
                return sys.stdin.read(1)
            return None
        finally:
            termios.tcsetattr(fd, termios.TCSADRAIN, old_settings)

    def elapsed(self):
        """Seconds since experiment start, rounded to 2 decimals."""
        return round(time.time() - self.start_time, 2)

    def log_event(self, timestamp, player='N/A'):
        self.data.append({'timestamp': timestamp, 'player': player})

    def update_last_player(self, player):
        if self.data:
            self.data[-1]['player'] = player

    def save(self):
        os.makedirs('data', exist_ok=True)
        condition = CONDITION_LABELS[self.condition]
        date_str  = datetime.now().strftime("%d%m%Y_%H%M%S")
        base      = f"data/{self.group_number}_{condition}_{date_str}"

        self._save_raw_csv(base, condition)
        summary = self._build_summary(condition)
        self.out(summary)
        self._save_summary_txt(base, summary)

    def _save_raw_csv(self, base, condition):
        filename = f"{base}.csv"
        with open(filename, 'w', newline='') as f:
            writer = csv.writer(f)
            writer.writerow(['group', 'condition', 'player_tagged', 'timestamp'])
            for row in self.data:
                writer.writerow([
                    self.group_number,
                    condition,
                    row['player'],
                    row['timestamp']
                ])
        self.out(f"\nRaw data: {filename}")

    def _build_summary(self, condition):
        rows        = self.data
        missing     = sum(1 for r in rows if r['player'] == 'N/A')
        is_estimate = missing > 0

        durations = {}

        # Spell duration for row i = timestamp[i+1] - timestamp[i]
        # Skip the first spell (timestamp == 0): that tagger was randomly assigned
        for i in range(len(rows) - 1):
            if rows[i]['timestamp'] == 0:
                continue
            if rows[i]['player'] == 'N/A':
                continue
            player   = str(rows[i]['player'])
            duration = rows[i + 1]['timestamp'] - rows[i]['timestamp']
            durations[player] = durations.get(player, 0) + duration

        # Add the final spell: from last tag to experiment end
        last_row = rows[-1]
        if last_row['timestamp'] != 0 and last_row['player'] != 'N/A':
            total_elapsed  = round(self.end_time - self.start_time, 2)
            final_duration = total_elapsed - last_row['timestamp']
            player         = str(last_row['player'])
            durations[player] = durations.get(player, 0) + final_duration

        # All players start at 0.0 so those never tagged still appear
        all_players = {str(i): 0.0 for i in range(1, NUM_PLAYERS + 1)}
        all_players.update(durations)

        sorted_players = sorted(all_players.items(), key=lambda x: x[1])
        min_time       = sorted_players[0][1]
        winners        = [p for p, t in sorted_players if t == min_time]

        lines = []
        lines.append(f"Group: {self.group_number}  Condition: {condition}")
        lines.append(f"Date:  {datetime.now().strftime('%d-%m-%Y %H:%M:%S')}")
        lines.append(f"Tags logged: {len(rows)}")
        lines.append("")
        lines.append("TIME AS TAGGER")
        if is_estimate:
            lines.append(f"(estimate - {missing} tag(s) missing player number)")
        for player, total in sorted_players:
            lines.append(f"  Player {player}: {total:.2f}s")
        lines.append("")
        if len(winners) == 1:
            lines.append(f"Winner (least time as tagger): Player {winners[0]} ({min_time:.2f}s)")
        else:
            lines.append(f"Draw ({min_time:.2f}s): Players {', '.join(winners)}")
        if is_estimate:
            lines.append("NOTE: Result is an estimate due to missing annotations")

        return "\n".join(lines)

    def _save_summary_txt(self, base, summary):
        filename = f"{base}_summary.txt"
        with open(filename, 'w') as f:
            for line in self.log:
                f.write(line + '\n')
            f.write('\n')
            f.write(summary + '\n')
        print(f"Summary:  {filename}")

    def check_time_limit(self):
        """Background thread: sets running=False when time is up."""
        while self.running:
            if time.time() - self.start_time >= EXPERIMENT_DURATION:
                self.end_time = self.start_time + EXPERIMENT_DURATION
                self.running  = False
                return
            time.sleep(0.1)

    def run(self):
        self.out("TAG EXPERIMENT TRACKER")
        self.out(f"Players: {NUM_PLAYERS}  |  Duration: {EXPERIMENT_DURATION}s\n")

        # Group number
        self.out("Group number (Enter to confirm):")
        group_input = ""
        while True:
            key = self.get_key()
            if key == '\x1b':
                print("\nAborted.")
                sys.exit(0)
            elif key is not None and key in ('\r', '\n'):
                if group_input:
                    self.group_number = group_input
                    self.out(f"Group: {self.group_number}\n")
                    break
            elif key is not None and key == '\x7f':
                if group_input:
                    group_input = group_input[:-1]
                    sys.stdout.write('\b \b')
                    sys.stdout.flush()
            elif key is not None and key.isalnum():
                group_input += key
                sys.stdout.write(key)
                sys.stdout.flush()

        # Condition
        self.out("Condition:  B = Baseline  |  W = Win  |  F = Fun")
        while True:
            key = self.get_key()
            if key == '\x1b':
                print("\nAborted.")
                sys.exit(0)
            elif key is not None and key.lower() in ['b', 'w', 'f']:
                self.condition = key.upper()
                condition_full = {'B': 'Baseline', 'W': 'Win', 'F': 'Fun'}[self.condition]
                self.out(f"Condition: {condition_full}\n")
                break

        # Random first tagger
        first_player = random.randint(1, NUM_PLAYERS)
        self.out(f"First tagger: Player {first_player}")
        self.out("\nPress SPACE to start...\n")
        while True:
            key = self.get_key()
            if key == ' ':
                break

        # Start experiment
        self.start_time = time.time()
        self.running    = True
        self.out("Experiment started!\n")
        self.out("  SPACE = log new tag")
        self.out(f"  1-{NUM_PLAYERS}   = add player number to last tag")
        self.out("  ESC   = end early and save\n")

        start_timestamp = self.elapsed()
        self.log_event(start_timestamp, first_player)
        self.out(f"[{start_timestamp:.2f}s] Start - Player {first_player} is tagger")

        threading.Thread(target=self.check_time_limit, daemon=True).start()

        valid_players = {str(i): i for i in range(1, NUM_PLAYERS + 1)}

        time_expired = False
        while self.running:
            key = self.get_key()
            if key is None:
                continue
            if key == '\x1b':
                break
            elif key == ' ':
                now            = self.elapsed()
                last_timestamp = self.data[-1]['timestamp']
                spell_duration = round(now - last_timestamp, 2)
                self.out(f"[{now:.2f}s] Duration: {spell_duration:.2f}s")
                self.log_event(now)
                self.out(f"[{now:.2f}s] Tag logged (player unknown)")
            elif key in valid_players:
                self.update_last_player(valid_players[key])
                last = self.data[-1]
                self.out(f"  -> Player {last['player']} added to [{last['timestamp']:.2f}s]")
        else:
            # while/else: only reached when self.running was set False by the time limit thread
            time_expired = True

        self.running = False
        if not time_expired:
            self.end_time = time.time()

        if time_expired:
            self.out("\nEXPERIMENT COMPLETE")
        else:
            self.out("\nENDED BY USER")

        self.save()


if __name__ == "__main__":
    working_dir = os.getcwd()
    if working_dir != EXPERIMENT_DIR:
        print(f"Error: Must be run from {EXPERIMENT_DIR}")
        print(f"Current directory: {working_dir}")
        sys.exit(1)

    experiment = TagExperiment()
    try:
        experiment.run()
    except Exception as e:
        print(f"\nError: {e}")
        if experiment.data:
            experiment.save()
